// --- COMPONENTE TELA CATEGORIAS ---
function TelaCategorias({ city, aoVoltar }: { city: string; aoVoltar: () => void }) {
  
  // LISTA COM OS SLUGS CORRETOS
  const categorias = [
    { id: 1, nome: "Restaurantes", img: "restaurantes.png", icon: "restaurant", slug: "restaurantes" },
    { id: 2, nome: "Farmácias", img: "farmacia.png", icon: "local_pharmacy", slug: "farmacias" },
    { id: 3, nome: "Supermercados", img: "supermercado.png", icon: "shopping_cart", slug: "supermercados" },
    { id: 4, nome: "Tabacaria", img: "tabacaria.png", icon: "smoking_rooms", slug: "tabacaria" },
    { id: 5, nome: "Bebidas", img: "bebidas.png", icon: "local_bar", slug: "bebidas" },
    { id: 6, nome: "Sex Shop", img: "sexshop.png", icon: "favorite", slug: "sex-shop" },
    { id: 7, nome: "Talho", img: "talho.png", icon: "restaurant_menu", slug: "talho" },
    { id: 8, nome: "Flores", img: "flores.png", icon: "local_florist", slug: "flores" },
  ];

  return (
    <>
      <a href="#" onClick={(e) => { e.preventDefault(); aoVoltar(); }}>
        <img id="logoini" src="/assets/img/logo.png" alt="Logo PedeJá" />
      </a>
      <div id="wave-top"></div>
      
      <div id="content" className="row justify-content-lg-center">
        <div className="d-lg-flex d-none col-lg-6 col-xl-5" id="div-left">
          <div id="base-left">
            <div id="imgbar" className="col-12">
              <img src="/assets/img/map.png" alt="Mapa" />
            </div>
            <div id="title" className="col-12">
              <h1>{city ? city.toUpperCase() : "CIDADE"}</h1>
            </div>
            <div id="subtitle" className="col-12">
              <h2>Desde Restaurantes a Tabacaria, Sex Shop e muito mais...</h2>
            </div>
          </div>
        </div>

        <div className="col-12 col-lg-6 col-xl-6" id="div-right">
          <div id="base-right">

            <ul id="tipo" className="col-12" style={{ 
                listStyle: 'none', 
                padding: 0,
                display: 'grid',              
                gridTemplateColumns: '1fr 1fr', 
                gap: '25px'
            }}>

              {categorias.map((cat) => (
                <li key={cat.id}> 
                  
                  {/* O LINK ENVOLVE O BOTÃO TODO */}
                  <Link href={`/${city.toLowerCase()}/${cat.slug}`} style={{ textDecoration: 'none', display: 'block' }}>

                    <div 
                      className="categoria-btn"
                      style={{ 
                        display: 'flex', 
                        alignItems: 'center', 
                        backgroundColor: 'white', 
                        padding: '15px 20px', 
                        borderRadius: '50px', 
                        cursor: 'pointer',
                        boxShadow: '0 4px 10px rgba(0,0,0,0.1)',
                        transition: 'transform 0.2s',
                        height: '100%',
                        width: '100%' 
                      }}
                      onMouseEnter={(e) => e.currentTarget.style.transform = 'scale(1.02)'}
                      onMouseLeave={(e) => e.currentTarget.style.transform = 'scale(1)'}
                    >
                      
                      <img 
                        src={`/assets/img/cats/${cat.img}`} 
                        alt={cat.nome}
                        style={{ width: '35px', height: '35px', marginRight: '15px', objectFit: 'contain' }}
                        onError={(e) => {
                          e.currentTarget.style.display = 'none';
                          e.currentTarget.nextElementSibling!.removeAttribute('hidden');
                        }}
                      />
                      
                      <span hidden className="material-icons" style={{ fontSize: '28px', color: '#dc3545', marginRight: '15px' }}>
                        {cat.icon}
                      </span>

                      <span style={{ 
                        fontSize: '16px', 
                        fontWeight: 'bold', 
                        color: '#333',
                        flex: 1, 
                        whiteSpace: 'nowrap',
                        overflow: 'hidden',
                        textOverflow: 'ellipsis' 
                      }}>
                        {cat.nome}
                      </span>

                      <span className="material-icons" style={{ marginLeft: '10px', color: '#ccc', fontSize: '24px' }}>
                        chevron_right
                      </span>
                      
                    </div>

                  </Link>

                </li>
              ))}
            </ul>

          </div>
        </div>
      </div>
      <div id="wave-bottom"></div>
      
      <span onClick={aoVoltar} className="material-icons" style={{
        position: 'fixed', bottom: '30px', right: '90px', 
        color: 'white', fontSize: '45px', cursor: 'pointer', zIndex: 999,
        textShadow: '0px 2px 5px rgba(0,0,0,0.2)'
      }}>
        arrow_back
      </span>
    </>
  );
}

// --- COMPONENTE PRINCIPAL ---
export default function Home() {
  const [tela, setTela] = useState<'inicio' | 'categorias'>('inicio');
  const [cidade, setCidade] = useState("");
  const [menuAberto, setMenuAberto] = useState(false);

  const irParaCategorias = (cidadeEscolhida: string) => {
    setCidade(cidadeEscolhida);
    setTela('categorias');
  };

  const voltarInicio = () => {
    setTela('inicio');
    setCidade("");
    setMenuAberto(false);
  };

  return (
    <main>
      {tela === 'inicio' ? (
        <TelaInicio aoClicarCidade={irParaCategorias} />
      ) : (
        <TelaCategorias city={cidade} aoVoltar={voltarInicio} />
      )}
      
      {/* Botão de Menu (Lado Direito) */}
      <span 
        id="menu-iconini" 
        className="material-icons" 
        onClick={() => setMenuAberto(true)}
        style={{cursor: 'pointer'}}
      >
        menu
      </span>

      {/* O MODAL */}
      <div 
        className={`modal fade ${menuAberto ? 'show' : ''}`} 
        id="menupop" 
        tabIndex={-1} 
        aria-hidden={!menuAberto}
        data-backdrop="static"
        style={{ 
          display: menuAberto ? 'block' : 'none', 
          backgroundColor: menuAberto ? 'rgba(0,0,0,0.5)' : 'transparent'
        }}
      >
        <div className="modal-dialog modal-dialog-centered">
          <div className="modal-content">
            <div className="modal-header">
              <h5 className="modal-title">Menu</h5>
              <button 
                type="button" 
                className="close-custom" 
                onClick={() => setMenuAberto(false)}
              >
                <span className="material-icons">close</span>
              </button>
            </div>
            <div className="modal-body">
              <button onClick={voltarInicio} className="menu-btn-custom">
                <span className="material-icons">home</span> Início
              </button>
              <a href="https://pedeja.pt/sobre.html" style={{textDecoration: 'none'}}>
                <button className="menu-btn-custom">
                  <span className="material-icons">info</span> Sobre
                </button>
              </a>
              <a href="https://pedeja.pt/contatos.html" style={{textDecoration: 'none'}}>
                <button className="menu-btn-custom">
                  <span className="material-icons">phone</span> Contatos
                </button>
              </a>
              <a href="https://pedeja.pt/politicas.html" style={{textDecoration: 'none'}}>
                <button className="menu-btn-custom">
                  <span className="material-icons">policy</span> Políticas de privacidade
                </button>
              </a>
              <a href="https://pedeja.pt/termos.html" style={{textDecoration: 'none'}}>
                <button className="menu-btn-custom">
                  <span className="material-icons">description</span> Termos e condições
                </button>
              </a>
            </div> 
          </div>
        </div>
      </div>
      
    </main>
  );
}